def sum_list(lst):
    if not lst:
        return 0
    return lst[0] + sum_list(lst[1:])

def factorial_tail(n, accumulator=1):
    if n == 1:
        return accumulator
    return factorial_tail(n - 1, n * accumulator)  # last operation

def fibonacci(n):
    if n <= 1:
        return n
    return fibonacci(n - 1) + fibonacci(n - 2)

def is_even(n):
    if n == 0: return True
    return is_odd(n - 1)

def is_odd(n):
    if n == 0: return False
    return is_even(n - 1)

def binary_search(arr, target, low, high):
    if low > high:          # base case: not found
        return -1
    mid = (low + high) // 2
    if arr[mid] == target:  # base case: found
        return mid
    elif target < arr[mid]:
        return binary_search(arr, target, low, mid - 1)
    else:
        return binary_search(arr, target, mid + 1, high)

def dfs(graph, node, visited=set()):
    if node in visited:
        return
    visited.add(node)
    print(node)
    for neighbor in graph[node]:
        dfs(graph, neighbor, visited)

def merge_sort(arr):
    if len(arr) <= 1:       # base case
        return arr
    mid = len(arr) // 2
    left = merge_sort(arr[:mid])
    right = merge_sort(arr[mid:])
    return merge(left, right)

def merge(left, right):
    result = []
    i = j = 0
    while i < len(left) and j < len(right):
        if left[i] <= right[j]:
            result.append(left[i]); i += 1
        else:
            result.append(right[j]); j += 1
    return result + left[i:] + right[j:]

def quicksort(arr):
    if len(arr) <= 1:
        return arr
    pivot = arr[len(arr) // 2]
    left  = [x for x in arr if x < pivot]
    mid   = [x for x in arr if x == pivot]
    right = [x for x in arr if x > pivot]
    return quicksort(left) + mid + quicksort(right)

def solve_n_queens(n):
    results = []
    board = [-1] * n  # board[row] = column of queen in that row

    def is_safe(row, col):
        for r in range(row):
            if board[r] == col or abs(board[r] - col) == abs(r - row):
                return False
        return True

    def backtrack(row):
        if row == n:
            results.append(board[:])
            return
        for col in range(n):
            if is_safe(row, col):
                board[row] = col
                backtrack(row + 1)
                board[row] = -1  # undo

    backtrack(0)
    return results

def knapsack(items, capacity):
    # items sorted by value/weight ratio descending
    if not items or capacity == 0:
        return 0
    item = items[0]
    weight = min(item['weight'], capacity)
    value = weight * (item['value'] / item['weight'])
    return value + knapsack(items[1:], capacity - weight)

def fib(n):
    if n <= 1: return n
    return fib(n-1) + fib(n-2)

# Infinite loop — n never changes
def bad(n):
    if n == 0: return 0
    return bad(n) + 1  # Should be bad(n-1)

def find(node, target):
